import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';

const MasterData = ({ role }) => {
  const navigate = useNavigate();
  const userRole = role || 'Guest'; // fallback langsung ke Guest jika role kosong

  const [form, setForm] = useState({
    truckId: '',
    truckType: '',
    driver: '',
    plateNumber: '',
    status: 'onprogress',
    date: '',
    image: null,
  });

  const [trucks, setTrucks] = useState([]);
  const [search, setSearch] = useState('');
  const [isRFIDScanned, setIsRFIDScanned] = useState(false);
  const [rfidValue, setRfidValue] = useState(null);
  const [isEditing, setIsEditing] = useState(false);
  const apiUrl = 'http://localhost:5000';

  // Polling RFID setiap 20 detik
  useEffect(() => {
    const interval = setInterval(async () => {
      if (isEditing) return;
      try {
        const res = await fetch(`${apiUrl}/api/rfid/latest`);
        if (!res.ok) throw new Error(`HTTP error! Status: ${res.status}`);
        const data = await res.json();

        if (data?.truck) {
          setIsRFIDScanned(true);
          setRfidValue(data.truck.truckId);
          const dateOnly = data.truck.date ? data.truck.date.split('T')[0] : '';
          setForm({
            truckId: data.truck.truckId || '',
            truckType: data.truck.truckType || '',
            driver: data.truck.driver || '',
            plateNumber: data.truck.plateNumber || '',
            status: data.truck.status || 'onprogress',
            date: dateOnly,
            image: null,
          });
          setIsEditing(true);
        } else if (data?.rfid) {
          setIsRFIDScanned(true);
          setRfidValue(data.rfid);
          setForm(prev => ({ ...prev, truckId: data.rfid }));
          setIsEditing(false);
        } else {
          setIsRFIDScanned(false);
          setRfidValue(null);
          setForm({ truckId: '', truckType: '', driver: '', plateNumber: '', status: 'onprogress', date: '', image: null });
          setIsEditing(false);
        }
      } catch (err) {
        console.error('Error fetching RFID:', err);
        setIsRFIDScanned(false);
        setRfidValue(null);
        setForm({ truckId: '', truckType: '', driver: '', plateNumber: '', status: 'onprogress', date: '', image: null });
        setIsEditing(false);
      }
    }, 20000);

    return () => clearInterval(interval);
  }, [isEditing]);

  // Fetch trucks dari server
  const fetchTrucks = async () => {
    try {
      const res = await fetch(`${apiUrl}/api/trucks`);
      const data = await res.json();
      if (res.ok) setTrucks(data);
    } catch (err) {
      console.error('Failed to fetch trucks:', err);
    }
  };

  useEffect(() => {
    fetchTrucks();
  }, []);

  const handleChange = (e) => {
    const { name, value, files } = e.target;
    if (name === 'image') setForm(prev => ({ ...prev, image: files[0] }));
    else setForm(prev => ({ ...prev, [name]: value }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!isRFIDScanned) return alert('Silakan scan kartu RFID terlebih dahulu!');

    const formData = new FormData();
    Object.entries(form).forEach(([key, val]) => {
      if (val) formData.append(key, val);
    });
    if (rfidValue) formData.append('rfid', rfidValue);

    try {
      const res = await fetch(`${apiUrl}/api/trucks`, { method: 'POST', body: formData });
      const data = await res.json();
      if (res.ok) {
        alert('Truck successfully saved!');
        setForm({ truckId: '', truckType: '', driver: '', plateNumber: '', status: 'onprogress', date: '', image: null });
        setIsRFIDScanned(false);
        setIsEditing(false);
        fetchTrucks();
      } else alert(data.message || 'Failed to save truck data');
    } catch (err) {
      alert('Connection to server failed');
      console.error(err);
    }
  };

  const handleDelete = async (truckId) => {
    if (!window.confirm('Are you sure you want to delete this truck?')) return;

    try {
      const res = await fetch(`${apiUrl}/api/trucks/${truckId}`, { method: 'DELETE' });
      const data = await res.json();
      if (res.ok) fetchTrucks();
      else alert(data.message || 'Failed to delete truck');
    } catch (err) {
      alert('Connection to server failed');
      console.error(err);
    }
  };

  const handleEdit = (truckId) => navigate(`/edit-truck/${truckId}`);

  const filteredTrucks = trucks.filter(truck =>
    truck.truckId.toLowerCase().includes(search.toLowerCase()) ||
    truck.truckType.toLowerCase().includes(search.toLowerCase()) ||
    truck.driver.toLowerCase().includes(search.toLowerCase()) ||
    (truck.plateNumber?.toLowerCase().includes(search.toLowerCase())) ||
    truck.status.toLowerCase().includes(search.toLowerCase())
  );

  return (
    <div className="flex min-h-screen bg-fixed bg-cover bg-center" style={{ background: 'linear-gradient(135deg, #43bfbf 0%, #076169 60%, #033c3b 100%)' }}>
      {/* Sidebar */}
      <aside className="bg-gray-800 text-white w-64 p-6 flex flex-col justify-between">
        <div>
          <div className="flex flex-col items-center mb-6">
            <img src="/images/admin.png" alt="User Icon" className="rounded-full mb-2" />
            <h2 className="font-semibold text-lg">{userRole}</h2>
          </div>
          <nav className="space-y-6">
            <Link to="/master-data" className="block bg-gray-700 rounded-lg p-3 text-center hover:text-white">Master Data</Link>
            {(userRole === 'Admin' || userRole === 'Super Admin') && (
              <>
                <Link to="/tracking" className="block bg-gray-700 rounded-lg p-3 text-center hover:text-white">Tracking</Link>
                <Link to="/info-driver" className="block bg-gray-700 rounded-lg p-3 text-center hover:text-white">Info Driver</Link>
              </>
            )}
            <Link to="/checkpoint" className="block bg-gray-700 rounded-lg p-3 text-center hover:text-white">Checkpoint</Link>
            <Link to="/timbang-muat" className="block bg-indigo-700 hover:bg-indigo-600 rounded-lg p-3 text-center">Timbang Muat</Link>
            <Link to="/timbang-gudang" className="block bg-indigo-700 hover:bg-indigo-600 rounded-lg p-3 text-center">Timbang Gudang</Link>
          </nav>
        </div>
        <nav className="space-y-6 mt-6">
          <Link to="/settings" className="block bg-gray-700 rounded-lg p-3 text-center hover:text-white">Settings</Link>
          <Link to="/logout" className="block bg-gray-700 rounded-lg p-3 text-center hover:text-white">Logout</Link>
        </nav>
      </aside>

      {/* Main Content */}
      <main className="flex-1 p-6">
        <header className="flex items-center justify-between mb-6">
          <h1 className="text-2xl font-bold">Dashboard / Truck</h1>
        </header>

        <div className={`mb-4 text-white p-3 rounded ${isRFIDScanned ? 'bg-green-500' : 'bg-red-500'}`}>
          {isRFIDScanned ? `RFID Terdeteksi: ${rfidValue}` : 'Silakan scan kartu RFID...'}
        </div>

        {/* Form Tambah Truck */}
        <section className={`mb-6 bg-white p-6 rounded-lg shadow-md space-y-4 ${isRFIDScanned ? '' : 'opacity-50 pointer-events-none'}`}>
          <h2 className="text-xl font-semibold mb-2">Tambah Truck Baru</h2>
          <form onSubmit={handleSubmit} className="space-y-4" encType="multipart/form-data">
            <div>
              <label>Truck ID</label>
              <input readOnly type="text" name="truckId" value={form.truckId} onChange={handleChange} required className="mt-1 p-2 border rounded w-full" />
            </div>
            <div>
              <label>Truck Type</label>
              <input type="text" name="truckType" value={form.truckType} onChange={handleChange} required className="mt-1 p-2 border rounded w-full" />
            </div>
            <div>
              <label>Driver</label>
              <input type="text" name="driver" value={form.driver} onChange={handleChange} required className="mt-1 p-2 border rounded w-full" />
            </div>
            <div>
              <label>Plate Number</label>
              <input type="text" name="plateNumber" value={form.plateNumber} onChange={handleChange} placeholder="B 1234 XYZ" required className="mt-1 p-2 border rounded w-full" />
            </div>
            <div>
              <label>Status</label>
              <select name="status" value={form.status} onChange={handleChange} className="mt-1 p-2 border rounded w-full">
                <option value="onprogress">On Progress</option>
                <option value="completed">Completed</option>
              </select>
            </div>
            <div>
              <label>Date</label>
              <input type="date" name="date" value={form.date} onChange={handleChange} required className="mt-1 p-2 border rounded w-full" />
            </div>
            <div>
              <label>Image (optional)</label>
              <input type="file" name="image" onChange={handleChange} accept="image/*" className="mt-1" />
            </div>
            <button type="submit" className="bg-blue-600 text-white px-4 py-2 rounded hover:bg-blue-700">Save</button>
          </form>
        </section>

        {/* Search Trucks */}
        <section className="mb-4">
          <input type="text" placeholder="Search trucks..." value={search} onChange={(e) => setSearch(e.target.value)} className="w-full p-2 border rounded" />
        </section>

        {/* List Trucks */}
        <section className="bg-white rounded-lg shadow-md p-6">
          <h2 className="text-xl font-semibold mb-4">List Trucks</h2>
          <table className="w-full border-collapse border border-gray-300">
            <thead>
              <tr className="bg-gray-200">
                <th className="border p-2">Image</th>
                <th className="border p-2">Truck ID</th>
                <th className="border p-2">Truck Type</th>
                <th className="border p-2">Driver</th>
                <th className="border p-2">Plate Number</th>
                <th className="border p-2">Status</th>
                <th className="border p-2">Date</th>
                <th className="border p-2">Actions</th>
              </tr>
            </thead>
            <tbody>
              {filteredTrucks.length > 0 ? (
                filteredTrucks.map(truck => (
                  <tr key={truck.truckId}>
                    <td className="border p-2">
                      {truck.image_url ? <img src={truck.image_url} alt="Truck" className="w-24 h-24 object-cover rounded" /> : <span>No Image</span>}
                    </td>
                    <td className="border p-2">{truck.truckId}</td>
                    <td className="border p-2">{truck.truckType}</td>
                    <td className="border p-2">{truck.driver}</td>
                    <td className="border p-2">{truck.plateNumber || '-'}</td>
                    <td className="border p-2">{truck.status}</td>
                    <td className="border p-2">{truck.date ? truck.date.split('T')[0] : ''}</td>
                    <td className="border p-2 space-x-2">
                      {userRole === 'Admin' ? (
                        <>
                          <button onClick={() => handleEdit(truck.truckId)} className="bg-yellow-500 text-white px-2 py-1 rounded hover:bg-yellow-600">Edit</button>
                          <button onClick={() => handleDelete(truck.truckId)} className="bg-red-600 text-white px-2 py-1 rounded hover:bg-red-700">Delete</button>
                        </>
                      ) : (
                        <>
                          <button disabled className="bg-yellow-500 text-white px-2 py-1 rounded opacity-50 cursor-not-allowed">Edit</button>
                          <button disabled className="bg-red-600 text-white px-2 py-1 rounded opacity-50 cursor-not-allowed">Delete</button>
                        </>
                      )}
                    </td>
                  </tr>
                ))
              ) : (
                <tr>
                  <td colSpan="8" className="text-center p-4">No trucks found</td>
                </tr>
              )}
            </tbody>
          </table>
        </section>
      </main>
    </div>
  );
};

export default MasterData;
